#include <bits/stdc++.h>
using namespace std;
const int mod=1e9+7;
int c[21];
unsigned long long l,r,ans[10],f[21];
void calc(long long n,int xs){
	int m=0;
	for(;n;n/=10)
		c[++m]=n%10;
	for(int i=1,j=m;i<j;i++,j--)
		swap(c[i],c[j]);
	for(int i=1;i<=m;i++){
		for(int j=1;j<i;j++)
			ans[c[j]]+=xs*c[i]*f[m-i];
		for(int j=1;j<c[i];j++)
			ans[j]+=xs*f[m-i];
		if(i!=1 && c[i])
			ans[0]+=xs*f[m-i];
		if(m!=i){
			for(int j=1;j<10;j++)
				ans[j]+=xs*f[m-i-1]*(m-i)*c[i];
			if(i!=1)
				ans[0]+=xs*f[m-i-1]*(m-i)*c[i];
		}
		if(i==1){
			if(m>1)
				ans[0]+=xs*(c[1]-1)*(m-1)*f[m-2];
			for(int j=2;j<m;j++)
				ans[0]+=xs*9*(m-j)*f[m-j-1];
		}
	}
	for(int i=1;i<=m;i++)
		ans[c[i]]+=xs;
}
int main(){
	int t;
	cin>>t;
	while(t--){
		f[0]=1;
		for(int i=1;i<=18;i++)
			f[i]=f[i-1]*10;
		cin>>l>>r;
		memset(ans,0,sizeof(ans));
		calc(r,1);
		calc(l-1,-1);
		unsigned long long sum=0;
		for(int i=0;i<=9;i++){
			//cout<<ans[i]<<endl;
			sum+=ans[i]*i,sum%=mod;
			//cout<<sum<<endl;
		}
		cout<<sum<<endl;
	}	
	return 0;
}
